{
var size = context.TileSize;
    var rx = GetFloat(parameters, "x", 0.25f);
    var ry = GetFloat(parameters, "y", 0.25f);
    var rw = GetFloat(parameters, "width", 0.5f);
    var rh = GetFloat(parameters, "height", 0.5f);
    var rectColor = GetColor(parameters, "color", Colors.White);
    var cornerRadius = GetFloat(parameters, "cornerRadius", 0f);
    var filled = GetBool(parameters, "filled", true);
    var strokeWidth = GetInt(parameters, "strokeWidth", 0);

    var cR = rectColor.R / 255f;
    var cG = rectColor.G / 255f;
    var cB = rectColor.B / 255f;

    // Compute pixel-space rectangle bounds
    var x0 = rx * size;
    var y0 = ry * size;
    var x1 = (rx + rw) * size;
    var y1 = (ry + rh) * size;

    var radius = cornerRadius * size;
    var halfStroke = strokeWidth * 0.5f;

    // Clone input buffer or create empty one
    PixelBuffer buffer;
    if (inputs.Length > 0 && inputs[0] != null)
    {
        buffer = inputs[0]!.Clone();
    }
    else
    {
        buffer = PixelBufferPool.Borrow(size, size);
    }

    buffer.ParallelForEachPixel((x, y) =>
    {
        var px = x + 0.5f;
        var py = y + 0.5f;

        // Signed distance to rectangle interior
        var d = SignedRectDistance(px, py, x0, y0, x1, y1, radius);

        float alpha;

        if (filled)
        {
            // Fill interior
            alpha = d <= 0f ? 1f : 0f;

            // Stroke overlay if strokeWidth > 0
            if (strokeWidth > 0)
            {
                var innerDist = d;
                var outerDist = SignedRectDistance(px, py, x0 - halfStroke, y0 - halfStroke, x1 + halfStroke, y1 + halfStroke, radius + halfStroke);
                if (innerDist > 0f && outerDist <= 0f)
                {
                    alpha = 1f;
                }
            }
        }
        else if (strokeWidth > 0)
        {
            // Stroke only
            var innerDist = SignedRectDistance(px, py, x0 + halfStroke, y0 + halfStroke, x1 - halfStroke, y1 - halfStroke, Math.Max(0f, radius - halfStroke));
            var outerDist = SignedRectDistance(px, py, x0 - halfStroke, y0 - halfStroke, x1 + halfStroke, y1 + halfStroke, radius + halfStroke);
            alpha = (innerDist > 0f && outerDist <= 0f) ? 1f : 0f;
        }
        else
        {
            alpha = 0f;
        }

        if (alpha <= 0f) return;

        var (or, og, ob, oa) = buffer.GetPixel(x, y);
        var outA = oa + alpha * (1f - oa);
        if (outA > 0f)
        {
            var outR = (or * oa + cR * alpha * (1f - oa)) / outA;
            var outG = (og * oa + cG * alpha * (1f - oa)) / outA;
            var outB = (ob * oa + cB * alpha * (1f - oa)) / outA;
            buffer.SetPixel(x, y, outR, outG, outB, outA);
        }
        else
        {
            buffer.SetPixel(x, y, cR, cG, cB, alpha);
        }
    });

    return buffer;

/// <summary>
/// Signed distance from point (px, py) to the axis-aligned rectangle with optional rounded corners.
/// Negative means inside the rectangle.
/// </summary>
private static float SignedRectDistance(float px, float py, float x0, float y0, float x1, float y1, float radius)
{
    // Closest point on rectangle boundary
    var cx = Math.Clamp(px, x0, x1);
    var cy = Math.Clamp(py, y0, y1);
    var dx = px - cx;
    var dy = py - cy;

    // Distance from point to nearest edge (positive = outside)
    var dist = MathF.Sqrt(dx * dx + dy * dy);

    if (radius > 0f)
    {
        // For rounded corners, the true distance requires checking corner regions
        // Get the signed distance to the inner rect (shrunk by radius)
        var innerX0 = x0 + radius;
        var innerY0 = y0 + radius;
        var innerX1 = x1 - radius;
        var innerY1 = y1 - radius;

        if (innerX1 < innerX0 || innerY1 < innerY0) radius = 0f;

        if (px >= innerX0 && px <= innerX1 && py >= innerY0 && py <= innerY1)
        {
            // Fully inside the inner rectangle
            var dLeft = px - x0;
            var dRight = x1 - px;
            var dTop = py - y0;
            var dBot = y1 - py;
            return -MathF.Min(MathF.Min(dLeft, dRight), MathF.Min(dTop, dBot));
        }

        if (px < innerX0 && py < innerY0)
        {
            // Top-left corner quadrant
            var cd = MathF.Sqrt((px - (x0 + radius)) * (px - (x0 + radius)) + (py - (y0 + radius)) * (py - (y0 + radius)));
            return cd - radius;
        }

        if (px > innerX1 && py < innerY0)
        {
            // Top-right corner quadrant
            var cd = MathF.Sqrt((px - (x1 - radius)) * (px - (x1 - radius)) + (py - (y0 + radius)) * (py - (y0 + radius)));
            return cd - radius;
        }

        if (px < innerX0 && py > innerY1)
        {
            // Bottom-left corner quadrant
            var cd = MathF.Sqrt((px - (x0 + radius)) * (px - (x0 + radius)) + (py - (y1 - radius)) * (py - (y1 - radius)));
            return cd - radius;
        }

        if (px > innerX1 && py > innerY1)
        {
            // Bottom-right corner quadrant
            var cd = MathF.Sqrt((px - (x1 - radius)) * (px - (x1 - radius)) + (py - (y1 - radius)) * (py - (y1 - radius)));
            return cd - radius;
        }

        // Edge regions: distance to nearest edge
        if (px < x0) return x0 - px;
        if (px > x1) return px - x1;
        if (py < y0) return y0 - py;
        if (py > y1) return py - y1;
        return -MathF.Min(px - x0, MathF.Min(x1 - px, MathF.Min(py - y0, y1 - py)));
    }

    // Non-rounded: if point is inside, return negative distance to nearest edge
    if (px >= x0 && px <= x1 && py >= y0 && py <= y1)
    {
        return -MathF.Min(px - x0, MathF.Min(x1 - px, MathF.Min(py - y0, y1 - py)));
    }

    return dist;
    }
}
